import{_ as t,c as i,o as r,ag as a}from"./chunks/framework.Dj4VfQLU.js";const u=JSON.parse('{"title":"Customer App Workflows","description":"","frontmatter":{"icon":"user"},"headers":[],"relativePath":"customer-app-workflows.md","filePath":"customer-app-workflows.md"}'),o={name:"customer-app-workflows.md"};function n(l,e,s,d,c,p){return r(),i("div",null,e[0]||(e[0]=[a('<h1 id="customer-app-workflows" tabindex="-1">Customer App Workflows <a class="header-anchor" href="#customer-app-workflows" aria-label="Permalink to &quot;Customer App Workflows&quot;">​</a></h1><p>The <strong>Customer App</strong> (<code>apps/taxi-rider-frontend/</code>) is a full-featured Flutter application that allows users to request ride-hailing or delivery services, track drivers in real-time, pay securely, and manage past activity. It&#39;s built with a clean architecture and real-time sync using WebSockets and GraphQL subscriptions, offering a seamless and responsive experience.</p><hr><h4 id="🧭-workflow-overview" tabindex="-1">🧭 Workflow Overview <a class="header-anchor" href="#🧭-workflow-overview" aria-label="Permalink to &quot;🧭 Workflow Overview&quot;">​</a></h4><ol><li>Sign up and verify account</li><li>Select service type and configure order</li><li>View fare estimate and confirm payment</li><li>Track driver and manage trip in real time</li><li>Rate experience and access trip history</li></ol><hr><h4 id="🪪-1-account-creation-verification" tabindex="-1">🪪 1. Account Creation &amp; Verification <a class="header-anchor" href="#🪪-1-account-creation-verification" aria-label="Permalink to &quot;🪪 1. Account Creation &amp; Verification&quot;">​</a></h4><ul><li>Users <strong>register directly</strong> in the app</li><li><strong>OTP verification</strong> is required for login and registration</li><li>Optionally, users can set a <strong>password</strong> for added security</li><li>Fare estimation and trip booking require account login</li></ul><hr><h4 id="📦-2-placing-an-order" tabindex="-1">📦 2. Placing an Order <a class="header-anchor" href="#📦-2-placing-an-order" aria-label="Permalink to &quot;📦 2. Placing an Order&quot;">​</a></h4><p><strong>Available Order Types:</strong></p><ul><li><strong>Ride-hailing</strong></li><li><strong>Parcel delivery</strong></li></ul><p>(Other options such as food or shop delivery are enabled when <strong>BetterShop</strong> is integrated)</p><p><strong>Booking Options:</strong></p><ul><li><strong>Immediate bookings</strong></li><li><strong>Scheduled (later) trips</strong> with date/time picker</li></ul><p><strong>Pre-Trip Configuration:</strong></p><ul><li>Choose pickup and drop-off (multi-stop supported)</li><li>Set <strong>wait time</strong>, if needed</li><li>Add <strong>special options</strong> (e.g., pet-friendly, luggage)</li><li>Select <strong>preferred vehicle type</strong> and <strong>payment method</strong></li></ul><blockquote><p>Customers must select a payment method prior to trip confirmation. Supported methods include:</p></blockquote><ul><li>Wallet</li><li>Saved cards (via integrated gateways)</li><li>Cash (if enabled by admin)</li></ul><hr><h4 id="💰-3-fare-estimate-promo-handling" tabindex="-1">💰 3. Fare Estimate &amp; Promo Handling <a class="header-anchor" href="#💰-3-fare-estimate-promo-handling" aria-label="Permalink to &quot;💰 3. Fare Estimate &amp; Promo Handling&quot;">​</a></h4><ul><li><strong>Fare estimation</strong> is displayed before confirmation, based on distance, time, and current multipliers</li><li><strong>Promo codes</strong> and <strong>Gift cards</strong> can be entered: <ul><li>From the <strong>wallet section</strong></li><li>Or during checkout via the ride options panel</li></ul></li><li>Applicable discounts are shown before final fare confirmation</li><li><strong>Cancellation fee warnings</strong> are displayed before placing the order</li></ul><hr><h4 id="🚗-4-real-time-tracking-notifications" tabindex="-1">🚗 4. Real-Time Tracking &amp; Notifications <a class="header-anchor" href="#🚗-4-real-time-tracking-notifications" aria-label="Permalink to &quot;🚗 4. Real-Time Tracking &amp; Notifications&quot;">​</a></h4><p>After booking:</p><ul><li>Real-time <strong>driver tracking</strong> is enabled on the map</li><li>The <strong>ETA</strong> is calculated once the driver accepts the trip</li><li>Status updates (e.g., driver en route, arrived, trip started, completed) are communicated via: <ul><li><strong>Push notifications</strong></li><li><strong>In-app status updates</strong></li></ul></li></ul><p><strong>🗺️ During the Trip:</strong></p><ul><li>User can: <ul><li>View live driver location</li><li>Contact the driver via <strong>in-app chat</strong></li><li>Access driver name, vehicle info, and contact options</li></ul></li></ul><hr><h4 id="💸-5-payments-wallet-management" tabindex="-1">💸 5. Payments &amp; Wallet Management <a class="header-anchor" href="#💸-5-payments-wallet-management" aria-label="Permalink to &quot;💸 5. Payments &amp; Wallet Management&quot;">​</a></h4><p><strong>Wallet Features:</strong></p><ul><li>Top-up wallet via integrated payment gateways</li><li>Apply <strong>promo codes</strong> or <strong>gift cards</strong> to balance</li><li>See transaction logs and wallet balance in real time</li></ul><p><strong>Payment Handling:</strong></p><ul><li>Charges are automatically deducted from the selected method upon trip completion</li><li>Invoices or receipts are shown in the <strong>Trip History section</strong></li><li>Wallet is also used for cancellations, refunds, and incentives</li></ul><hr><h4 id="📊-6-trip-history-ratings" tabindex="-1">📊 6. Trip History &amp; Ratings <a class="header-anchor" href="#📊-6-trip-history-ratings" aria-label="Permalink to &quot;📊 6. Trip History &amp; Ratings&quot;">​</a></h4><ul><li>Users can view all past rides and deliveries under <strong>Trip History</strong></li><li>After each completed trip: <ul><li>Users are prompted to <strong>rate the driver</strong></li><li>Select <strong>quality metrics</strong> (cleanliness, punctuality, etc.)</li></ul></li><li>If the trip is <strong>canceled</strong>, the app: <ul><li>Requires a <strong>cancellation reason</strong></li><li>Applies <strong>cancellation fees</strong> based on admin rules</li></ul></li></ul><hr><h4 id="💬-7-in-app-features" tabindex="-1">💬 7. In-App Features <a class="header-anchor" href="#💬-7-in-app-features" aria-label="Permalink to &quot;💬 7. In-App Features&quot;">​</a></h4><p><strong>Chat</strong></p><ul><li>Available after a driver is assigned</li><li>Secure and session-bound communication</li><li>Optionally backed by SMS if configured on the backend</li></ul><p><strong>Announcements</strong></p><ul><li>Persistent updates appear in a dedicated <strong>Announcements section</strong><ul><li>Service outages</li><li>Promotions</li><li>Regional notices</li></ul></li></ul><p><strong>Preferences</strong></p><ul><li>Users can: <ul><li>Switch between <strong>Light/Dark mode</strong></li><li>Change and <strong>persist language selection</strong></li><li>View app version and license info</li></ul></li></ul><hr><h4 id="📝-summary-workflow" tabindex="-1">📝 Summary Workflow <a class="header-anchor" href="#📝-summary-workflow" aria-label="Permalink to &quot;📝 Summary Workflow&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Step</th><th>Description</th></tr></thead><tbody><tr><td>Register &amp; Verify</td><td>OTP login + optional password setup</td></tr><tr><td>Create Booking</td><td>Select ride or delivery, configure details</td></tr><tr><td>View Fare &amp; Confirm</td><td>Apply promo/gift cards, review price</td></tr><tr><td>Track Driver</td><td>Live tracking, chat, and notifications</td></tr><tr><td>Complete &amp; Rate</td><td>Leave feedback and review trip summary</td></tr><tr><td>Manage Wallet</td><td>Top-up, view history, apply codes</td></tr><tr><td>Access History &amp; Reports</td><td>Past trips, cancellations, and receipts</td></tr><tr><td>Change Settings</td><td>Theme and language options available</td></tr></tbody></table>',48)]))}const m=t(o,[["render",n]]);export{u as __pageData,m as default};
